 16	interface OutputEnvelope {
 17	  command: string;
 18	  version: 1;
 19	  status: CliStatus;
 20	  outcome: string;
 21	  result?: unknown;
 22	  errors: CliError[];
 23	  warnings: string[];
 24	  artifacts: CliArtifactRef[];
 25	  startedAt: string;
 26	  finishedAt: string;
 27	}
 28	
 29	function collectRepeatedFlag(rawArgs: string[], flag: string): string[] {
 30	  const values: string[] = [];
 31	
 32	  for (let index = 0; index < rawArgs.length; index += 1) {
 33	    const value = rawArgs[index];
 34	    if (value === flag) {
 35	      const nextValue = rawArgs[index + 1];
 36	      if (nextValue && !nextValue.startsWith("--")) {
 37	        values.push(nextValue);
 38	      }
 39	      continue;
 40	    }
 41	
 42	    if (value.startsWith(`${flag}=`)) {
 43	      values.push(value.slice(flag.length + 1));
 44	    }
 45	  }
 46	
 47	  return values;
 48	}
 49	
 50	function renderHumanSummary(envelope: OutputEnvelope) {
 51	  if (
 52	    typeof envelope.result !== "object" ||
 53	    envelope.result === null ||
 54	    !("confirmedIssues" in envelope.result)
 55	  ) {
 56	    return `epic-synthesize: ${envelope.outcome}`;
 57	  }
 58	
 59	  const result = envelope.result as {
 60	    confirmedIssues: string[];
 61	    disputedOrUnconfirmedIssues: string[];
 62	  };
 63	  return [
 64	    `epic-synthesize: ${envelope.outcome}`,
 65	    `confirmed: ${result.confirmedIssues.length}`,
 66	    `disputed: ${result.disputedOrUnconfirmedIssues.length}`,
 67	  ].join("\n");
 68	}
 69	
 70	function emitOutput(params: {
 71	  envelope: OutputEnvelope;
 72	  json: boolean;
 73	}) {
 74	  if (params.json) {
 75	    console.log(JSON.stringify(params.envelope));
 76	    return;
 77	  }
 78	
 79	  console.log(renderHumanSummary(params.envelope));
 80	}
