 82	export default defineCommand({
 83	  meta: {
 84	    name: "epic-synthesize",
 85	    description: "Independently verify and synthesize epic verifier findings.",
 86	  },
 87	  args: {
 88	    "spec-pack-root": {
 89	      type: "string",
 90	      description: "Absolute or relative path to the spec-pack root",
 91	      required: true,
 92	    },
 93	    "verifier-report": {
 94	      type: "string",
 95	      description:
 96	        "Path to an epic verifier report artifact. Repeat the flag to pass multiple reports.",
 97	    },
 98	    config: {
 99	      type: "string",
100	      description: "Explicit run-config file relative to the spec-pack root",
101	    },
102	    json: {
103	      type: "boolean",
104	      description: "Emit the structured JSON envelope on stdout",
105	    },
106	  },
107	  async run({ args, rawArgs }) {
108	    const startedAt = new Date().toISOString();
109	    const artifactPath = await nextGroupedArtifactPath(
110	      args["spec-pack-root"],
111	      "epic",
112	      "epic-synthesis"
113	    );
114	
115	    try {
116	      const verifierReportPaths = collectRepeatedFlag(rawArgs, "--verifier-report");
117	      if (verifierReportPaths.length === 0) {
118	        const envelope: OutputEnvelope = createResultEnvelope({
119	          command: "epic-synthesize",
120	          outcome: "error",
121	          errors: [
122	            {
123	              code: "INVALID_INVOCATION",
124	              message: "Provide at least one --verifier-report path.",
125	            },
126	          ],
127	          artifacts: [
128	            {
129	              kind: "result-envelope",
130	              path: artifactPath,
131	            },
132	          ],
133	          startedAt,
134	          finishedAt: new Date().toISOString(),
135	        });
136	
137	        await writeJsonArtifact(artifactPath, envelope);
138	        emitOutput({
139	          envelope,
140	          json: Boolean(args.json),
141	        });
142	        process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
143	        return;
144	      }
145	
146	      const outcome = await runEpicSynthesize({
147	        specPackRoot: args["spec-pack-root"],
148	        verifierReportPaths,
149	        configPath: args.config,
150	        env: process.env,
151	      });
152	      const envelope = cliResultEnvelopeSchema(
153	        epicSynthesisResultSchema
154	      ).parse(
155	        createResultEnvelope({
156	          command: "epic-synthesize",
157	          outcome: outcome.outcome,
158	          result: outcome.result,
159	          errors: outcome.errors,
160	          warnings: outcome.warnings,
161	          artifacts: [
162	            {
163	              kind: "result-envelope",
164	              path: artifactPath,
165	            },
166	          ],
167	          startedAt,
168	          finishedAt: new Date().toISOString(),
169	        })
170	      );
171	
172	      await writeJsonArtifact(artifactPath, envelope);
173	      emitOutput({
174	        envelope,
175	        json: Boolean(args.json),
176	      });
177	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
178	    } catch (error) {
179	      const envelope: OutputEnvelope = createResultEnvelope({
180	        command: "epic-synthesize",
181	        outcome:
182	          error instanceof ZodError ||
183	          (error instanceof Error &&
184	            error.message.toLowerCase().includes("config"))
185	            ? "blocked"
186	            : "error",
187	        errors: [
188	          {
189	            code:
190	              error instanceof ZodError ||
191	              (error instanceof Error &&
192	                error.message.toLowerCase().includes("config"))
193	                ? "INVALID_RUN_CONFIG"
194	                : "UNEXPECTED_ERROR",
195	            message: error instanceof Error ? error.message : String(error),
196	          },
197	        ],
198	        artifacts: [
199	          {
200	            kind: "result-envelope",
201	            path: artifactPath,
202	          },
203	        ],
204	        startedAt,
205	        finishedAt: new Date().toISOString(),
206	      });
207	
208	      await writeJsonArtifact(artifactPath, envelope);
209	      emitOutput({
210	        envelope,
211	        json: Boolean(args.json),
212	      });
213	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
214	    }
215	  },
216	});

