404	function statusForOutcome(outcome: string): CliStatus {
405	  switch (outcome) {
406	    case "ready":
407	    case "ready-for-verification":
408	    case "needs-followup-fix":
409	    case "pass":
410	    case "revise":
411	    case "cleaned":
412	    case "needs-more-cleanup":
413	    case "ready-for-closeout":
414	    case "needs-fixes":
415	    case "needs-more-routing":
416	    case "needs-more-verification":
417	      return "ok";
418	    case "block":
419	      return "blocked";
420	    case "needs-user-decision":
421	    case "needs-human-ruling":
422	      return "needs-user-decision";
423	    case "blocked":
424	      return "blocked";
425	    default:
426	      return "error";
427	  }
428	}
