438	export function exitCodeForStatus(status: CliStatus, outcome?: string): number {
439	  switch (status) {
440	    case "ok":
441	      return outcome && !zeroExitOutcomes.has(outcome) ? 2 : 0;
442	    case "needs-user-decision":
443	      return 2;
444	    case "blocked":
445	      return 3;
446	    case "error":
447	    default:
448	      return 1;
449	  }
450	}
