 65	export async function inspectSpecPack(specPackRoot: string): Promise<InspectResult> {
 66	  const resolvedRoot = resolve(specPackRoot);
 67	  const epicPath = join(resolvedRoot, "epic.md");
 68	  const techDesignPath = join(resolvedRoot, "tech-design.md");
 69	  const testPlanPath = join(resolvedRoot, "test-plan.md");
 70	  const storiesDir = join(resolvedRoot, "stories");
 71	  const storiesFile = join(resolvedRoot, "stories.md");
 72	  const blockers: string[] = [];
 73	  const notes: string[] = [];
 74	
 75	  const repoRoot = await resolveGitRepoRoot(resolvedRoot);
 76	  if (!repoRoot) {
 77	    blockers.push(`Spec-pack root is not inside a git repo: ${resolvedRoot}`);
 78	  }
 79	
 80	  if (!(await pathExists(epicPath))) {
 81	    blockers.push("Missing required artifact: epic.md");
 82	  }
 83	
 84	  if (!(await pathExists(techDesignPath))) {
 85	    blockers.push("Missing required artifact: tech-design.md");
 86	  }
 87	
 88	  if (!(await pathExists(testPlanPath))) {
 89	    blockers.push("Missing required artifact: test-plan.md");
 90	  }
 91	
 92	  const storiesDirExists = await pathIsDirectory(storiesDir);
 93	  if (!storiesDirExists && (await pathExists(storiesFile))) {
 94	    blockers.push("Expected stories/ directory but found stories.md");
 95	  } else if (!storiesDirExists) {
 96	    blockers.push("Missing required artifact: stories/");
 97	  }
 98	
 99	  const rootEntries = await readdir(resolvedRoot);
100	  const techDesignArtifacts = resolveTechDesignArtifacts(rootEntries);
101	  blockers.push(...techDesignArtifacts.blockers);
102	
103	  const storyOrder = storiesDirExists
104	    ? await resolveStoryOrder(storiesDir)
105	    : { status: "ready" as const, stories: [], notes: [] };
106	  notes.push(...storyOrder.notes);
107	  const implInsertPath = join(
108	    resolvedRoot,
109	    "custom-story-impl-prompt-insert.md"
110	  );
111	  const verifierInsertPath = join(
112	    resolvedRoot,
113	    "custom-story-verifier-prompt-insert.md"
114	  );
115	  const implInsertExists = await pathExists(implInsertPath);
116	  const verifierInsertExists = await pathExists(verifierInsertPath);
117	
118	  if (implInsertExists && !(await pathReadable(implInsertPath))) {
119	    blockers.push(
120	      "Unreadable prompt insert: custom-story-impl-prompt-insert.md"
121	    );
122	  }
123	
124	  if (verifierInsertExists && !(await pathReadable(verifierInsertPath))) {
125	    blockers.push(
126	      "Unreadable prompt insert: custom-story-verifier-prompt-insert.md"
127	    );
128	  }
129	
130	  const status =
131	    blockers.length > 0
132	      ? "blocked"
133	      : storyOrder.status === "needs-user-decision"
134	        ? "needs-user-decision"
135	        : "ready";
136	
137	  const result: InspectResult = {
138	    status,
139	    specPackRoot: resolvedRoot,
140	    techDesignShape: techDesignArtifacts.techDesignShape,
141	    artifacts: {
142	      epicPath,
143	      techDesignPath,
144	      techDesignCompanionPaths: techDesignArtifacts.companionPaths.map((file) =>
145	        join(resolvedRoot, file)
146	      ),
147	      testPlanPath,
148	      storiesDir,
149	    },
150	    stories: storyOrder.stories,
151	    inserts: {
152	      customStoryImplPromptInsert: implInsertExists ? "present" : "absent",
153	      customStoryVerifierPromptInsert: verifierInsertExists
154	        ? "present"
155	        : "absent",
156	    },
157	    blockers,
158	    notes,
159	  };
160	
161	  return inspectResultSchema.parse(result);
162	}

