  7	export interface GateDiscoveryResult {
  8	  status: "ready" | "needs-user-decision";
  9	  verificationGates?: {
 10	    storyGate: string;
 11	    epicGate: string;
 12	    storyGateSource: string;
 13	    epicGateSource: string;
 14	  };
 15	  errors: CliError[];
 16	  notes: string[];
 17	}
 18	
 19	interface GateSourceCandidates {
 20	  story: string[];
 21	  epic: string[];
 22	  source: string;
 23	}
 24	
 25	function uniqueValues(values: string[]): string[] {
 26	  return [...new Set(values.map((value) => value.trim()).filter(Boolean))];
 27	}
 28	
 29	function resolveGateValue(input: {
 30	  explicitValue?: string;
 31	  sourceCandidates: GateSourceCandidates[];
 32	  gate: "story" | "epic";
 33	}): {
 34	  value?: string;
 35	  source?: string;
 36	  ambiguous: boolean;
 37	} {
 38	  if (input.explicitValue) {
 39	    return {
 40	      value: input.explicitValue,
 41	      source: "explicit CLI flag",
 42	      ambiguous: false,
 43	    };
 44	  }
 45	
 46	  for (const candidateSet of input.sourceCandidates) {
 47	    const values = uniqueValues(candidateSet[input.gate]);
 48	    if (values.length > 1) {
 49	      return {
 50	        ambiguous: true,
 51	      };
 52	    }
 53	
 54	    if (values.length === 1) {
 55	      return {
 56	        value: values[0],
 57	        source: candidateSet.source,
 58	        ambiguous: false,
 59	      };
 60	    }
 61	  }
 62	
 63	  return {
 64	    ambiguous: false,
 65	  };
 66	}
