 68	async function packageScriptCandidates(
 69	  specPackRoot: string
 70	): Promise<GateSourceCandidates[]> {
 71	  const packageJsonPath = join(specPackRoot, "package.json");
 72	  if (!(await pathExists(packageJsonPath))) {
 73	    return [];
 74	  }
 75	
 76	  const packageJson = JSON.parse(await readTextFile(packageJsonPath)) as {
 77	    scripts?: Record<string, string>;
 78	  };
 79	  const scripts = packageJson.scripts ?? {};
 80	
 81	  if (!scripts["green-verify"] && !scripts["verify-all"]) {
 82	    return [];
 83	  }
 84	
 85	  return [
 86	    {
 87	      story: scripts["green-verify"] ? [scripts["green-verify"]] : [],
 88	      epic: scripts["verify-all"] ? [scripts["verify-all"]] : [],
 89	      source: "package.json scripts",
 90	    },
 91	  ];
 92	}
 93	
 94	async function docCandidates(specPackRoot: string): Promise<GateSourceCandidates[]> {
 95	  const candidates: GateSourceCandidates = {
 96	    story: [],
 97	    epic: [],
 98	    source: "project policy docs",
 99	  };
100	
101	  for (const fileName of ["AGENTS.md", "README.md"]) {
102	    const filePath = join(specPackRoot, fileName);
103	    if (!(await pathExists(filePath))) {
104	      continue;
105	    }
106	
107	    const content = await readTextFile(filePath);
108	    for (const match of content.matchAll(/^Story Gate:\s*(.+)$/gim)) {
109	      candidates.story.push(match[1]);
110	    }
111	    for (const match of content.matchAll(/^Epic Gate:\s*(.+)$/gim)) {
112	      candidates.epic.push(match[1]);
113	    }
114	  }
115	
116	  if (candidates.story.length === 0 && candidates.epic.length === 0) {
117	    return [];
118	  }
119	
120	  return [candidates];
121	}
