160	export async function resolveVerificationGates(input: {
161	  specPackRoot: string;
162	  explicitStoryGate?: string;
163	  explicitEpicGate?: string;
164	}): Promise<GateDiscoveryResult> {
165	  const specPackRoot = resolve(input.specPackRoot);
166	  const sourceCandidates = [
167	    ...(await packageScriptCandidates(specPackRoot)),
168	    ...(await docCandidates(specPackRoot)),
169	    ...(await ciCandidates(specPackRoot)),
170	  ];
171	  const storyResolution = resolveGateValue({
172	    explicitValue: input.explicitStoryGate,
173	    sourceCandidates,
174	    gate: "story",
175	  });
176	  const epicResolution = resolveGateValue({
177	    explicitValue: input.explicitEpicGate,
178	    sourceCandidates,
179	    gate: "epic",
180	  });
181	
182	  if (
183	    storyResolution.ambiguous ||
184	    epicResolution.ambiguous ||
185	    !storyResolution.value ||
186	    !epicResolution.value ||
187	    !storyResolution.source ||
188	    !epicResolution.source
189	  ) {
190	    return {
191	      status: "needs-user-decision",
192	      errors: [
193	        {
194	          code: "VERIFICATION_GATE_UNRESOLVED",
195	          message: "Verification gate policy is ambiguous",
196	          detail:
197	            "Provide --story-gate and --epic-gate explicitly or clarify the project policy.",
198	        },
199	      ],
200	      notes: [],
201	    };
202	  }
203	
204	  return {
205	    status: "ready",
206	    verificationGates: {
207	      storyGate: storyResolution.value,
208	      epicGate: epicResolution.value,
209	      storyGateSource: storyResolution.source,
210	      epicGateSource: epicResolution.source,
211	    },
212	    errors: [],
213	    notes: [],
214	  };
215	}

