288	async function loadPublicInsert(
289	  path: string | undefined
290	): Promise<{ assetId?: string; content?: string }> {
291	  if (!path || !(await pathExists(path))) {
292	    return {};
293	  }
294	
295	  const file = Bun.file(path);
296	  if (file.size > MAX_PUBLIC_INSERT_BYTES) {
297	    throw new PromptInsertError(
298	      `Public prompt insert exceeds ${MAX_PUBLIC_INSERT_BYTES} bytes: ${path}`
299	    );
300	  }
301	
302	  try {
303	    return {
304	      assetId: basename(path),
305	      content: await readTextFile(path),
306	    };
307	  } catch (error) {
308	    throw new PromptInsertError(
309	      `Public prompt insert could not be read: ${path}${
310	        error instanceof Error ? ` (${error.message})` : ""
311	      }`
312	    );
313	  }
314	}
