 49	    }
 50	  }
 51	
 52	  return undefined;
 53	}
 54	
 55	function parseNestedJson(value: unknown): unknown {
 56	  if (typeof value !== "string") {
 57	    return value;
 58	  }
 59	
 60	  try {
 61	    return JSON.parse(value);
 62	  } catch {
 63	    return undefined;
 64	  }
 65	}
 66	
 67	function formatIssuePath(path: ReadonlyArray<PropertyKey>): string {
 68	  if (path.length === 0) {
 69	    return "<root>";
 70	  }
 71	
 72	  return path.reduce<string>((formatted, segment) => {
 73	    if (typeof segment === "number") {
 74	      return `${formatted}[${segment}]`;
 75	    }
 76	
 77	    const label = typeof segment === "symbol" ? segment.toString() : segment;
 78	    return formatted.length === 0 ? label : `${formatted}.${label}`;
 79	  }, "");
 80	}
 81	
 82	function formatZodIssue(issue: z.ZodIssue): string {
 83	  if (issue.code === "unrecognized_keys") {
 84	    return `unexpected key(s) at ${formatIssuePath(issue.path)}: ${issue.keys.join(", ")}`;
 85	  }
 86	
 87	  if (issue.path.length === 0) {
 88	    return issue.message;
 89	  }
 90	
 91	  return `${formatIssuePath(issue.path)}: ${issue.message}`;
 92	}
 93	
 94	function formatZodError(error: z.ZodError): string {
 95	  return error.issues.map(formatZodIssue).join("; ");
 96	}
 97	
 98	export function parseProviderPayload<TResult>(input: {
 99	  stdout: string;
100	  resultSchema?: z.ZodType<TResult>;
101	}): {
102	  parsedResult?: TResult;
103	  sessionId?: string;
104	  parseError?: string;
105	} {
106	  const trimmed = input.stdout.trim();
107	  if (trimmed.length === 0) {
108	    return {
109	      parseError: "Provider stdout was empty.",
110	    };
111	  }
112	
113	  let root: unknown;
114	  try {
115	    root = JSON.parse(trimmed);
116	  } catch {
117	    return {
118	      parseError: "Provider stdout was not exact JSON.",
119	    };
120	  }
121	
122	  if (!root || typeof root !== "object" || Array.isArray(root)) {
123	    return {
124	      parseError: "Provider stdout was not a JSON object.",
125	    };
126	  }
127	
128	  const rootRecord = root as Record<string, unknown>;
129	  const resultSchema = input.resultSchema ?? z.unknown();
130	  const direct = resultSchema.safeParse(rootRecord);
131	  if (direct.success) {
132	    return {
133	      parsedResult: direct.data as TResult,
134	      sessionId: extractSessionId(rootRecord),
135	    };
136	  }
137	
138	  const parseDiagnostics = [`direct payload: ${formatZodError(direct.error)}`];
139	  for (const field of ["result", "text"]) {
140	    if (!(field in rootRecord)) {
141	      continue;
142	    }
143	
144	    const nested = parseNestedJson(rootRecord[field]);
145	    if (typeof rootRecord[field] === "string" && nested === undefined) {
146	      parseDiagnostics.push(`${field} payload: wrapper value was not valid JSON`);
147	      continue;
148	    }
149	
150	    const parsed = resultSchema.safeParse(nested);
151	    if (parsed.success) {
152	      return {
153	        parsedResult: parsed.data as TResult,
154	        sessionId: extractSessionId(rootRecord),
155	      };
156	    }
157	
158	    parseDiagnostics.push(`${field} payload: ${formatZodError(parsed.error)}`);
159	  }
160	
161	  return {
162	    parseError: `Provider output did not match the expected JSON payload. ${parseDiagnostics.join("; ")}`,
163	  };
164	}
