166	export async function runProviderCommand(params: {
167	  provider: ProviderName;
168	  executable: string;
169	  args: string[];
170	  cwd: string;
171	  env?: Record<string, string | undefined>;
172	  timeoutMs: number;
173	}): Promise<{
174	  provider: ProviderName;
175	  stdout: string;
176	  stderr: string;
177	  exitCode: number;
178	  errorCode?: string;
179	}> {
180	  try {
181	    const result = await execFileAsync(params.executable, params.args, {
182	      cwd: params.cwd,
183	      env: {
184	        ...process.env,
185	        ...params.env,
186	      },
187	      timeout: params.timeoutMs,
188	    });
189	
190	    return {
191	      provider: params.provider,
192	      stdout: redactSensitiveText(result.stdout.trim()),
193	      stderr: redactSensitiveText(result.stderr.trim()),
194	      exitCode: 0,
195	    };
196	  } catch (error) {
197	    const failed = error as {
198	      code?: string | number;
199	      stdout?: string;
200	      stderr?: string;
201	      message?: string;
202	    };
203	
204	    return {
205	      provider: params.provider,
206	      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
207	      stderr: redactSensitiveText(
208	        failed.stderr?.trim() ?? failed.message ?? String(error)
209	      ),
210	      exitCode:
211	        typeof failed.code === "number" ? failed.code : 1,
212	      errorCode:
213	        typeof failed.code === "string" ? failed.code : undefined,
214	    };
215	  }
216	}

