357	  provider: ProviderName;
358	  sessionId: string;
359	}): Promise<string | null> {
360	  const artifactsRoot = join(resolve(input.specPackRoot), "artifacts");
361	  if (!(await pathExists(artifactsRoot))) {
362	    return null;
363	  }
364	
365	  const groups = await readdir(artifactsRoot, { withFileTypes: true });
366	  for (const group of groups) {
367	    if (!group.isDirectory()) {
368	      continue;
369	    }
370	
371	    const groupPath = join(artifactsRoot, group.name);
372	    const entries = await readdir(groupPath, { withFileTypes: true });
373	    for (const entry of entries) {
374	      if (!entry.isFile() || !entry.name.endsWith(".json")) {
375	        continue;
376	      }
377	
378	      try {
379	        const content = JSON.parse(
380	          await readTextFile(join(groupPath, entry.name))

381	        ) as {
382	          result?: {
383	            continuation?: {
384	              provider?: string;
385	              sessionId?: string;
386	              storyId?: string;
387	            };
388	          };
389	        };
390	        const continuation = content.result?.continuation;
391	        if (
392	          continuation?.provider === input.provider &&
393	          continuation?.sessionId === input.sessionId
394	        ) {
395	          return continuation.storyId ?? group.name;
396	        }
397	      } catch {}
398	    }
399	  }
400	
401	  return null;
