114	  const inspection = await inspectSpecPack(input.specPackRoot);
115	  if (inspection.status !== "ready") {
116	    return {
117	      outcome: "block",
118	      errors: [
119	        blockedError(
120	          "INVALID_SPEC_PACK",
121	          "Spec-pack inspection must be ready before story verification can start.",
122	          inspection.blockers.join("; ") || inspection.notes.join("; ")
123	        ),
124	      ],
125	    };
126	  }
127	
128	  const story = inspection.stories.find((candidate) => candidate.id === input.storyId);
129	  if (!story) {
130	    return {
131	      outcome: "block",
132	      errors: [
133	        blockedError(
134	          "INVALID_SPEC_PACK",
135	          `Story '${input.storyId}' was not found in the resolved story inventory.`
136	        ),
137	      ],
138	    };
139	  }
140	
141	  const config = await loadRunConfig({
142	    specPackRoot: inspection.specPackRoot,
143	    configPath: input.configPath,
144	  });
145	  const gateResolution = await resolveVerificationGates({
146	    specPackRoot: inspection.specPackRoot,
147	  });
148	  if (gateResolution.status !== "ready" || !gateResolution.verificationGates) {
149	    return {
150	      outcome: "block",
151	      errors: gateResolution.errors.length
152	        ? gateResolution.errors
153	        : [
154	            blockedError(
155	              "VERIFICATION_GATE_UNRESOLVED",
156	              "Verification gates must be resolved before story verification can start."
157	            ),
158	          ],
159	    };
160	  }
161	
162	  return {
163	    specPackRoot: inspection.specPackRoot,
164	    story: {
165	      id: story.id,
166	      title: story.title,
167	      path: story.path,
