 74	function executionFailureError(input: {
 75	  provider: ProviderName;
 76	  stderr: string;
 77	  errorCode?: string;
 78	}): CliError {
 79	  if (input.errorCode === "ENOENT") {
 80	    return blockedError(
 81	      "PROVIDER_UNAVAILABLE",
 82	      `Provider executable is unavailable for ${input.provider}.`,
 83	      input.stderr
 84	    );
 85	  }
 86	
