 94	function parseVerifierReportContent(content: string): EpicVerifierResult[] | undefined {
 95	  let parsed: unknown;
 96	  try {
 97	    parsed = JSON.parse(content);
 98	  } catch {
 99	    return undefined;
100	  }
101	
102	  const directResult = epicVerifierResultSchema.safeParse(parsed);
103	  if (directResult.success) {
104	    return [directResult.data];
105	  }
106	
107	  const directBatch = epicVerifierBatchResultSchema.safeParse(parsed);
108	  if (directBatch.success) {
109	    return directBatch.data.verifierResults;
110	  }
111	
112	  const envelope = cliResultEnvelopeSchema(epicVerifierBatchResultSchema).safeParse(
113	    parsed
114	  );
115	  if (envelope.success && envelope.data.result) {
116	    return envelope.data.result.verifierResults;
117	  }
118	
119	  return undefined;
120	}
