258	function buildSynthesisResult(payload: ProviderPayload): EpicSynthesisResult {
259	  return {
260	    resultId: randomUUID(),
261	    outcome: payload.outcome,
262	    confirmedIssues: payload.confirmedIssues,
263	    disputedOrUnconfirmedIssues: payload.disputedOrUnconfirmedIssues,
264	    readinessAssessment: payload.readinessAssessment,
265	    recommendedNextStep: payload.recommendedNextStep,
266	  };
