269	export async function runEpicSynthesize(input: {
270	  specPackRoot: string;
271	  verifierReportPaths: string[];
272	  configPath?: string;
273	  env?: Record<string, string | undefined>;
274	}): Promise<EpicSynthesisWorkflowResult> {
275	  const context = await prepareSynthesisContext(input);
276	  if ("errors" in context) {
277	    return {
278	      outcome: "blocked",
279	      errors: context.errors,
280	      warnings: [],
281	    };
282	  }
283	
284	  const prompt = await assemblePrompt({
285	    role: "epic_synthesizer",
286	    epicPath: context.paths.epicPath,
287	    techDesignPath: context.paths.techDesignPath,
288	    techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
289	    testPlanPath: context.paths.testPlanPath,
290	    verifierReportPaths: context.verifierReportPaths,
291	    gateCommands: context.gateCommands,
292	  });
293	  const adapter = createProviderAdapter(context.provider, {
294	    env: input.env,
295	  });
296	  const execution = await adapter.execute({
297	    prompt: prompt.prompt,
298	    cwd: context.specPackRoot,
299	    model: context.model,
300	    reasoningEffort: context.reasoningEffort,
301	    timeoutMs: 30_000,
302	    resultSchema: providerPayloadSchema,
303	  });
304	
305	  if (execution.exitCode !== 0) {
306	    return {
307	      outcome: "blocked",
308	      errors: [
309	        executionFailureError({
310	          provider: context.provider,
311	          stderr: execution.stderr,
312	          errorCode: execution.errorCode,
313	        }),
314	      ],
315	      warnings: [],
316	    };
317	  }
318	
319	  if (execution.parseError || !execution.parsedResult) {
320	    return {
321	      outcome: "blocked",
322	      errors: [
323	        blockedError(
324	          "PROVIDER_OUTPUT_INVALID",
325	          `Provider output was invalid for ${context.provider}.`,
326	          execution.parseError
327	        ),
328	      ],
329	      warnings: [],
330	    };
331	  }
332	
333	  const result = buildSynthesisResult(execution.parsedResult);
334	  return {
335	    outcome: result.outcome,
336	    result,
337	    errors: [],
338	    warnings: [],
339	  };
340	}

