 83	async function readSourceFile(relativePath: string): Promise<string> {
 84	  const fullPath = join(SRC, relativePath);
 85	  const file = Bun.file(fullPath);
 86	  const exists = await file.exists();
 87	  if (!exists) {
 88	    console.error(`ERROR: Source file not found: ${fullPath}`);
 89	    process.exit(1);
 90	  }
 91	  return file.text();
 92	}
