118	async function zipDirectory(
119	  archiveName: string,
120	  directoryName: string,
121	  cwd: string
122	): Promise<void> {
123	  const proc = Bun.spawn(["zip", "-r", archiveName, directoryName], {
124	    cwd,
125	    stdout: "pipe",
126	    stderr: "pipe",
127	  });
128	  const exitCode = await proc.exited;
129	  if (exitCode !== 0) {
130	    const stderr = await new Response(proc.stderr).text();
131	    throw new Error(
132	      `zip failed for ${archiveName} (exit ${exitCode}): ${stderr.trim()}`
133	    );
134	  }
135	}
