155	async function validateSkills(): Promise<void> {
156	  const glob = new Glob("*/SKILL.md");
157	  const paths: string[] = [];
158	
159	  for await (const match of glob.scan({ cwd: DIST_SKILLS, absolute: true })) {
160	    paths.push(match);
161	  }
162	
163	  if (paths.length === 0) {
164	    result.errors.push("No skill files found in dist/skills/");
165	    return;
166	  }
167	
168	  for (const skillPath of paths.sort()) {
169	    const content = await readFile(skillPath);
170	    const skillName = skillPath.split("/").at(-2) ?? "unknown";
171	
172	    if (!hasFrontmatter(content)) {
173	      result.errors.push(`Skill '${skillName}': missing YAML frontmatter`);
174	      continue;
175	    }
176	
177	    const parsed = parseFrontmatter(content);
178	
179	    if (!parsed.data.name || typeof parsed.data.name !== "string") {
180	      result.errors.push(`Skill '${skillName}': frontmatter missing 'name'`);
181	    }
182	    if (
183	      !parsed.data.description ||
184	      typeof parsed.data.description !== "string"
185	    ) {
186	      result.errors.push(
187	        `Skill '${skillName}': frontmatter missing 'description'`
188	      );
189	    }
190	
191	    const bodyContent = parsed.content.trim();
192	    if (bodyContent.length === 0) {
193	      result.errors.push(
194	        `Skill '${skillName}': no content after frontmatter`
195	      );
196	    }
197	
198	    const lineCount = content.split("\n").length;
199	    console.log(`  skill: ${skillName} (${lineCount} lines)`);
200	    result.skillsValid++;
201	  }
202	}
