14	async function loadTextDirectory(dir: string): Promise<Record<string, string>> {
15	  const entries = await readdir(dir, { withFileTypes: true });
16	  const result: Record<string, string> = {};
17	
18	  for (const entry of entries) {
19	    if (!entry.isFile()) {
20	      continue;
21	    }
22	    result[entry.name] = await readFile(join(dir, entry.name), "utf8");
23	  }
24	
25	  return Object.fromEntries(
26	    Object.entries(result).sort(([left], [right]) => left.localeCompare(right))
27	  );
28	}
